import{_ as a,c as i,o as t,aj as s}from"./chunks/framework.guNMSiFm.js";const p=JSON.parse('{"title":"Data Modeling","description":"","frontmatter":{},"headers":[],"relativePath":"guide/best-practices/data-modeling.md","filePath":"guide/best-practices/data-modeling.md","lastUpdated":1777621302000}'),n={name:"guide/best-practices/data-modeling.md"};function o(r,e,d,l,c,h){return t(),i("div",null,[...e[0]||(e[0]=[s('<h1 id="data-modeling" tabindex="-1">Data Modeling <a class="header-anchor" href="#data-modeling" aria-label="Permalink to &quot;Data Modeling&quot;">​</a></h1><p>Ledger data should be modeled around ownership, transfer behavior, permission boundaries, and query patterns. Choose the smallest on-chain representation that can support auditability and deterministic execution.</p><h2 id="domains-and-accounts" tabindex="-1">Domains and Accounts <a class="header-anchor" href="#domains-and-accounts" aria-label="Permalink to &quot;Domains and Accounts&quot;">​</a></h2><ul><li>Use domains to represent administrative and policy boundaries. Keep domain names stable because they appear in account and asset identifiers.</li><li>Avoid overloading a single account with unrelated responsibilities. Use separate accounts for users, services, triggers, operators, and fee sponsors.</li><li>Use canonical account and domain identifiers in config and tests. Iroha names are case-sensitive after canonical parsing.</li><li>Keep test and production identities visibly distinct in names, domains, and configuration file paths.</li></ul><p>See <a href="/iroha-2-docs/blockchain/domains.html">Domains</a>, <a href="/iroha-2-docs/blockchain/accounts.html">Accounts</a>, and <a href="/iroha-2-docs/reference/naming.html">Naming</a>.</p><h2 id="assets-and-nfts" tabindex="-1">Assets and NFTs <a class="header-anchor" href="#assets-and-nfts" aria-label="Permalink to &quot;Assets and NFTs&quot;">​</a></h2><ul><li>Use numeric assets for fungible balances and transferable quantities.</li><li>Use NFTs or domain-specific objects for uniquely owned records.</li><li>Avoid encoding value-bearing state only in metadata. Assets and NFTs provide lifecycle events, transfer semantics, and permission checks that metadata does not.</li><li>Define precision, supply policy, issuer responsibility, and burn/mint authority before exposing an asset to applications.</li></ul><p>See <a href="/iroha-2-docs/blockchain/assets.html">Assets</a>, <a href="/iroha-2-docs/blockchain/nfts.html">NFTs</a>, and <a href="/iroha-2-docs/blockchain/rwas.html">RWAs</a>.</p><h2 id="metadata" tabindex="-1">Metadata <a class="header-anchor" href="#metadata" aria-label="Permalink to &quot;Metadata&quot;">​</a></h2><ul><li>Use metadata for compact attributes of ledger objects, such as labels, integration IDs, policy flags, hashes, URIs, or content-addressed references.</li><li>Keep metadata keys stable and documented. Changing key names after clients depend on them creates a migration problem.</li><li>Do not store large documents, logs, private user data, or high-churn application state directly in metadata.</li><li>When metadata points to off-chain data, store a verifiable reference such as a content hash, URI, SoraFS path, manifest reference, or compact commitment.</li></ul><p>See <a href="/iroha-2-docs/guide/configure/metadata-and-store-assets.html">Metadata and Ledger Storage Choices</a> and <a href="/iroha-2-docs/blockchain/metadata.html">Metadata</a>.</p><h2 id="permissions-by-model" tabindex="-1">Permissions by Model <a class="header-anchor" href="#permissions-by-model" aria-label="Permalink to &quot;Permissions by Model&quot;">​</a></h2><ul><li>Design roles around business operations, not around implementation conveniences. A role named after a job or service is easier to audit than a role named after a broad technical capability.</li><li>Scope permission tokens to the smallest object that satisfies the workflow.</li><li>Treat permissions for minting, burning, peer management, executor changes, trigger management, and metadata mutation as high-impact permissions.</li><li>Add explicit revocation and rotation procedures for temporary permissions.</li></ul><p>See <a href="/iroha-2-docs/blockchain/permissions.html">Permissions</a> and <a href="/iroha-2-docs/reference/permissions.html">Permission Tokens</a>.</p><h2 id="query-shape" tabindex="-1">Query Shape <a class="header-anchor" href="#query-shape" aria-label="Permalink to &quot;Query Shape&quot;">​</a></h2><ul><li>Choose identifiers and metadata keys that support the queries your application will need most often.</li><li>Paginate broad result sets and avoid user interfaces that require unrestricted ledger-wide scans for normal actions.</li><li>Keep off-chain indexes reconstructible from ledger data and events whenever they are used for critical application behavior.</li></ul>',16)])])}const u=a(n,[["render",o]]);export{p as __pageData,u as default};
